// src/components/sections/Hero.js
import React, { useEffect, useRef, useState } from "react";
import { motion, useViewportScroll, useTransform, useMotionValue, useSpring } from "framer-motion";
import { 
  Github, 
  Linkedin, 
  Mail, 
  Download, 
  ArrowRight, 
  ChevronDown, 
  Terminal, 
  Code2, 
  Server, 
  Cpu, 
  Zap, 
  Layers, 
  Cloud, 
  Database, 
  Globe, 
  Briefcase, 
  Award 
} from "lucide-react";
import Button from "../ui/Button";
import { scrollToSection } from "../../utils/helpers";
import { PERSONAL_INFO, SOCIAL_LINKS } from "../../utils/constants";

const Hero = () => {
  const containerRef = useRef(null);
  const { scrollY } = useViewportScroll();
  const [typedText, setTypedText] = useState("");
  const [isDeleting, setIsDeleting] = useState(false);
  const [loopNum, setLoopNum] = useState(0);
  const [matrixLines, setMatrixLines] = useState([]);
  const [displayText, setDisplayText] = useState("");
  const [isMobile, setIsMobile] = useState(false);
  
  const phrases = [
    "Full Stack Developer",
    "System Architect",
    "Cloud Engineer",
    "DevOps Specialist",
    "Tech Lead"
  ];

  // ✅ Hooks must be called unconditionally - move outside conditional
  const mouseX = useMotionValue(0);
  const mouseY = useMotionValue(0);
  const springX = useSpring(mouseX, { damping: 30, stiffness: 200 });
  const springY = useSpring(mouseY, { damping: 30, stiffness: 200 });
  
  // ✅ These useTransform hooks must be called unconditionally at top level
  const transformX = useTransform(springX, (v) => -v * 0.5);
  const transformY = useTransform(springY, (v) => -v * 0.5);

  // Check mobile
  useEffect(() => {
    const checkMobile = () => {
      setIsMobile(window.innerWidth < 768);
    };
    checkMobile();
    window.addEventListener('resize', checkMobile);
    return () => window.removeEventListener('resize', checkMobile);
  }, []);

  // Hacker Screen Matrix Effect
  useEffect(() => {
    const chars = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ!@#$%^&*()";
    const lines = [];
    const numLines = isMobile ? 20 : 40;
    
    for (let i = 0; i < numLines; i++) {
      const lineLength = Math.floor(Math.random() * 40) + 20;
      let line = "";
      for (let j = 0; j < lineLength; j++) {
        line += chars[Math.floor(Math.random() * chars.length)];
      }
      lines.push({
        id: i,
        text: line,
        x: Math.random() * 100,
        speed: 0.5 + Math.random() * 2,
        delay: Math.random() * 10,
        opacity: 0.1 + Math.random() * 0.3
      });
    }
    setMatrixLines(lines);
  }, [isMobile]);

  // Terminal display text effect
  useEffect(() => {
    const terminalTexts = [
      "> Initializing system...",
      "> Loading modules...",
      "> Connecting to neural network...",
      "> System ready.",
      "> Welcome to my portfolio.",
      "> Let's build something amazing."
    ];
    
    let index = 0;
    let charIndex = 0;
    let currentText = "";
    
    const typeInterval = setInterval(() => {
      if (charIndex < terminalTexts[index].length) {
        currentText += terminalTexts[index][charIndex];
        setDisplayText(currentText);
        charIndex++;
      } else {
        index++;
        charIndex = 0;
        currentText = "";
        if (index >= terminalTexts.length) {
          clearInterval(typeInterval);
        }
      }
    }, isMobile ? 80 : 50);
    
    return () => clearInterval(typeInterval);
  }, [isMobile]);

  // Typing effect
  useEffect(() => {
    const handleTyping = () => {
      const currentPhrase = phrases[loopNum % phrases.length];
      const isComplete = typedText === currentPhrase;
      
      if (isDeleting) {
        setTypedText(currentPhrase.substring(0, typedText.length - 1));
        if (typedText === "") {
          setIsDeleting(false);
          setLoopNum(loopNum + 1);
        }
      } else {
        setTypedText(currentPhrase.substring(0, typedText.length + 1));
        if (typedText === currentPhrase) {
          setTimeout(() => setIsDeleting(true), 2000);
        }
      }
    };

    const timer = setTimeout(handleTyping, isDeleting ? 50 : 100);
    return () => clearTimeout(timer);
  }, [typedText, isDeleting, loopNum]);

  // Mouse tracking - disabled on mobile
  useEffect(() => {
    if (isMobile) return;

    const handleMouse = (e) => {
      const rect = containerRef.current?.getBoundingClientRect();
      if (rect) {
        const x = (e.clientX - rect.left) / rect.width - 0.5;
        const y = (e.clientY - rect.top) / rect.height - 0.5;
        mouseX.set(x * 30);
        mouseY.set(y * 30);
      }
    };
    window.addEventListener("mousemove", handleMouse);
    return () => window.removeEventListener("mousemove", handleMouse);
  }, [mouseX, mouseY, isMobile]);

  // Digital particles
  const getParticles = () => {
    const count = isMobile ? 15 : 40;
    return Array.from({ length: count }, (_, i) => ({
      id: i,
      x: Math.random() * 100,
      y: Math.random() * 100,
      size: Math.random() * 2 + 1,
      duration: Math.random() * 20 + 15,
      delay: Math.random() * 5,
      opacity: Math.random() * 0.2 + 0.05,
    }));
  };

  const digitalParticles = getParticles();

  // Matrix rain effect
  const matrixRain = () => {
    const chars = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ";
    return Array.from({ length: isMobile ? 30 : 60 }, (_, i) => ({
      id: i,
      char: chars[Math.floor(Math.random() * chars.length)],
      x: Math.random() * 100,
      y: Math.random() * 100,
      speed: 0.5 + Math.random() * 3,
      size: 8 + Math.random() * 14,
      opacity: 0.1 + Math.random() * 0.3
    }));
  };

  const matrixChars = matrixRain();

  return (
    <section
      ref={containerRef}
      id="home"
      className="relative w-full min-h-screen overflow-hidden bg-[#0a0a0a]"
    >
      {/* ===== HACKER MATRIX BACKGROUND ===== */}
      <div className="absolute inset-0 overflow-hidden opacity-30">
        {/* Matrix Rain */}
        {matrixChars.map((char) => (
          <motion.div
            key={char.id}
            className="absolute font-mono text-green-500/50"
            style={{
              left: `${char.x}%`,
              fontSize: `${char.size}px`,
              opacity: char.opacity,
            }}
            animate={{
              y: [-100, 110],
              opacity: [0, char.opacity, 0],
            }}
            transition={{
              duration: char.speed * 2,
              repeat: Infinity,
              delay: Math.random() * 5,
              ease: "linear",
            }}
          >
            {char.char}
          </motion.div>
        ))}

        {/* Matrix Grid Lines */}
        <div className="absolute inset-0" style={{
          backgroundImage: `
            linear-gradient(rgba(0, 255, 0, 0.03) 1px, transparent 1px),
            linear-gradient(90deg, rgba(0, 255, 0, 0.03) 1px, transparent 1px)
          `,
          backgroundSize: '50px 50px'
        }} />

        {/* Scanning Line */}
        <motion.div
          className="absolute left-0 right-0 h-[2px] bg-green-500/20 shadow-lg shadow-green-500/50"
          animate={{ top: ['0%', '100%'] }}
          transition={{ duration: 8, repeat: Infinity, ease: "linear" }}
        />
      </div>

      {/* Hacker Terminal Overlay */}
      <div className="absolute inset-0 bg-gradient-to-b from-transparent via-black/20 to-black/80" />

      {/* Digital Particles */}
      {digitalParticles.map((p) => (
        <motion.div
          key={p.id}
          className="absolute rounded-full bg-green-400"
          style={{
            width: p.size,
            height: p.size,
            left: `${p.x}%`,
            top: `${p.y}%`,
            opacity: p.opacity,
          }}
          animate={{
            y: [0, -50, 0],
            x: [0, 25, 0],
          }}
          transition={{
            duration: p.duration,
            repeat: Infinity,
            delay: p.delay,
            ease: "easeInOut",
          }}
        />
      ))}

      {/* ✅ Animated Gradient Orbs - Use transformX and transformY that are defined above */}
      {!isMobile && (
        <>
          <motion.div
            style={{ x: springX, y: springY }}
            className="absolute -top-40 -right-40 w-[600px] h-[600px] rounded-full bg-green-500/5 blur-3xl"
            animate={{ scale: [1, 1.2, 1] }}
            transition={{ duration: 8, repeat: Infinity }}
          />
          <motion.div
            style={{ x: transformX, y: transformY }}
            className="absolute -bottom-40 -left-40 w-[500px] h-[500px] rounded-full bg-cyan-500/5 blur-3xl"
            animate={{ scale: [1, 1.3, 1] }}
            transition={{ duration: 10, repeat: Infinity, delay: 2 }}
          />
        </>
      )}

      {/* ===== MAIN CONTENT ===== */}
      <div className="relative z-10 container mx-auto px-4 sm:px-6 h-screen flex items-center">
        <div className="grid lg:grid-cols-2 gap-8 lg:gap-12 items-center w-full">
          
          {/* LEFT COLUMN - Text Content with Terminal Style */}
          <motion.div
            initial={{ opacity: 0, x: -30 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.8 }}
            className="space-y-4 sm:space-y-6 text-center lg:text-left order-2 lg:order-1"
          >
            {/* Terminal Header */}
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.1 }}
              className="inline-flex items-center gap-2 px-3 py-1.5 rounded-lg bg-black/60 border border-green-500/30 backdrop-blur-sm mx-auto lg:mx-0 font-mono"
            >
              <span className="w-1.5 h-1.5 rounded-full bg-green-400 animate-pulse" />
              <span className="text-green-400 text-[10px] sm:text-xs">root@portfolio:~$</span>
              <span className="text-green-400/50 text-[10px] sm:text-xs">— ONLINE</span>
            </motion.div>

            {/* Terminal Display Text */}
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.2 }}
              className="font-mono text-xs sm:text-sm text-green-400/70 bg-black/40 p-2 sm:p-3 rounded-lg border border-green-500/10 max-w-lg mx-auto lg:mx-0"
            >
              <div className="flex items-start gap-2">
                <span className="text-green-500">$</span>
                <span>{displayText}</span>
                <span className="animate-pulse">█</span>
              </div>
            </motion.div>

            {/* Name - Hacker Style */}
            <motion.div
              initial={{ opacity: 0, y: 30 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.3 }}
            >
              <h1 className="text-3xl sm:text-5xl md:text-6xl lg:text-7xl xl:text-8xl font-bold leading-tight">
                <span className="text-gray-400">I'm </span>
                <span className="bg-gradient-to-r from-green-400 via-cyan-400 to-blue-400 bg-clip-text text-transparent block sm:inline">
                  {PERSONAL_INFO.name}
                </span>
              </h1>
            </motion.div>

            {/* Dynamic Typing Title - Hacker Style */}
            <motion.div
              initial={{ opacity: 0, y: 30 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.4 }}
              className="font-mono"
            >
              <div className="text-base sm:text-xl md:text-2xl text-green-400">
                <span className="text-gray-500">$</span> 
                <span className="text-green-300">./</span>
                {typedText}
                <span className="animate-pulse text-green-400">|</span>
              </div>
            </motion.div>

            {/* Description */}
            <motion.p
              initial={{ opacity: 0, y: 30 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.5 }}
              className="text-gray-400 max-w-lg text-sm sm:text-base md:text-lg leading-relaxed mx-auto lg:mx-0"
            >
              {PERSONAL_INFO.description}
            </motion.p>

            {/* Stats - Hacker Style */}
            <motion.div
              initial={{ opacity: 0, y: 30 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.55 }}
              className="flex flex-wrap justify-center lg:justify-start gap-4 sm:gap-8 pt-2"
            >
              <div className="flex items-center gap-2 sm:gap-3">
                <div className="p-1.5 sm:p-2 rounded-lg bg-green-500/10 border border-green-400/20">
                  <Briefcase className="w-4 h-4 sm:w-5 sm:h-5 text-green-400" />
                </div>
                <div>
                  <div className="text-green-400 font-bold text-base sm:text-lg">4.5+</div>
                  <div className="text-gray-500 text-[10px] sm:text-xs font-mono">Years</div>
                </div>
              </div>
              <div className="flex items-center gap-2 sm:gap-3">
                <div className="p-1.5 sm:p-2 rounded-lg bg-cyan-500/10 border border-cyan-400/20">
                  <Award className="w-4 h-4 sm:w-5 sm:h-5 text-cyan-400" />
                </div>
                <div>
                  <div className="text-cyan-400 font-bold text-base sm:text-lg">12+</div>
                  <div className="text-gray-500 text-[10px] sm:text-xs font-mono">Projects</div>
                </div>
              </div>
              <div className="flex items-center gap-2 sm:gap-3">
                <div className="p-1.5 sm:p-2 rounded-lg bg-blue-500/10 border border-blue-400/20">
                  <Globe className="w-4 h-4 sm:w-5 sm:h-5 text-blue-400" />
                </div>
                <div>
                  <div className="text-blue-400 font-bold text-base sm:text-lg">8+</div>
                  <div className="text-gray-500 text-[10px] sm:text-xs font-mono">Clients</div>
                </div>
              </div>
            </motion.div>

            {/* Tech Stack Tags */}
            <motion.div
              initial={{ opacity: 0, y: 30 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.6 }}
              className="flex flex-wrap justify-center lg:justify-start gap-1.5 sm:gap-2 overflow-x-auto pb-2"
            >
              {["React", "Node.js", "TypeScript", "AWS", "Docker", "Kubernetes", "Go", "Python"].map((tag, i) => (
                <span
                  key={i}
                  className="px-2 sm:px-3 py-0.5 sm:py-1 text-[10px] sm:text-xs font-mono rounded-md bg-black/40 border border-green-500/20 text-green-400 hover:border-green-400/50 hover:text-green-300 hover:bg-green-500/10 transition-all cursor-default whitespace-nowrap"
                >
                  # {tag}
                </span>
              ))}
            </motion.div>

            {/* CTA Buttons - Hacker Style */}
            <motion.div
              initial={{ opacity: 0, y: 30 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.65 }}
              className="flex flex-wrap justify-center lg:justify-start gap-3 sm:gap-4 pt-2"
            >

             <button
                onClick={() => window.open("/psahoo-react-node.pdf", "_blank")}
                className="border-2 border-green-500/30 hover:border-green-400/60 text-green-400 hover:text-green-300 bg-black/40 backdrop-blur-sm px-6 sm:px-8 py-2 sm:py-3 rounded-lg text-sm sm:text-base font-mono flex items-center justify-center transition-all duration-300"
              >
                <Download className="w-4 h-4 mr-2" />
                Download CV
              </button>
              <button
                onClick={() => scrollToSection("contact")}
                className="group bg-gradient-to-r from-green-500 to-cyan-500 hover:from-green-600 hover:to-cyan-600 text-white px-6 sm:px-8 py-2 sm:py-3 rounded-lg shadow-lg shadow-green-500/20 text-sm sm:text-base font-mono flex items-center justify-center transition-all duration-300"
              >
                <span className="text-green-300 group-hover:text-white transition">$</span>
                Get In Touch
                <ArrowRight className="w-4 h-4 ml-2 group-hover:translate-x-1 transition-transform" />
              </button>
             
            </motion.div>

            {/* Social Links */}
            <motion.div
              initial={{ opacity: 0, y: 30 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.7 }}
              className="flex justify-center lg:justify-start gap-3 sm:gap-4 pt-2"
            >
              {[
                { href: SOCIAL_LINKS.github, icon: Github, label: "GitHub", color: "hover:text-white" },
                { href: SOCIAL_LINKS.linkedin, icon: Linkedin, label: "LinkedIn", color: "hover:text-blue-400" },
                { href: `mailto:${PERSONAL_INFO.email}`, icon: Mail, label: "Email", color: "hover:text-red-400" },
              ].map((social, i) => (
                <motion.a
                  key={i}
                  href={social.href}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="p-2 sm:p-3 rounded-lg bg-black/40 backdrop-blur-sm border border-green-500/20 text-gray-400 hover:bg-green-500/10 hover:border-green-400/50 transition-all duration-300 group"
                  whileHover={{ scale: 1.1, y: -3 }}
                  whileTap={{ scale: 0.95 }}
                >
                  <social.icon className={`w-4 h-4 sm:w-5 sm:h-5 group-hover:scale-110 transition-all ${social.color}`} />
                </motion.a>
              ))}
            </motion.div>
          </motion.div>

          {/* ===== RIGHT COLUMN - Profile Image ===== */}
          <motion.div
            initial={{ opacity: 0, scale: 0.8 }}
            animate={{ opacity: 1, scale: 1 }}
            transition={{ duration: 0.8, delay: 0.2 }}
            className="flex justify-center items-center mt-6 lg:mt-0 order-1 lg:order-2"
          >
            <div className="relative">
              {/* Animated Rings - Hidden on mobile */}
              <motion.div
                className="absolute inset-0 rounded-full border-2 border-green-400/20 hidden sm:block"
                animate={{ scale: [1, 1.1, 1], rotate: [0, 360] }}
                transition={{ duration: 20, repeat: Infinity, ease: "linear" }}
                style={{ width: "120%", height: "120%", top: "-10%", left: "-10%" }}
              />
              <motion.div
                className="absolute inset-0 rounded-full border-2 border-cyan-400/20 hidden sm:block"
                animate={{ scale: [1, 1.2, 1], rotate: [360, 0] }}
                transition={{ duration: 25, repeat: Infinity, ease: "linear" }}
                style={{ width: "140%", height: "140%", top: "-20%", left: "-20%" }}
              />

              {/* Profile Image */}
              <motion.div
                className="relative w-40 h-40 xs:w-48 xs:h-48 sm:w-56 sm:h-56 md:w-64 md:h-64 lg:w-72 lg:h-72 rounded-full overflow-hidden border-4 border-green-400/30 shadow-2xl shadow-green-500/20 mx-auto"
                whileHover={{ scale: 1.05 }}
                transition={{ duration: 0.3 }}
              >
                <img
                  src={PERSONAL_INFO.profileImage}
                  alt={PERSONAL_INFO.name}
                  className="w-full h-full object-cover"
                  onError={(e) => {
                    e.target.src = "https://ui-avatars.com/api/?name=" + PERSONAL_INFO.name.replace(" ", "+") + "&background=0a0a0a&color=22c55e&size=200";
                  }}
                />
                
                {/* Overlay gradient */}
                <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent" />
                
                {/* Scanner Effect on Image */}
                <motion.div
                  className="absolute inset-0 bg-gradient-to-b from-transparent via-green-500/10 to-transparent"
                  animate={{ top: ['-100%', '100%'] }}
                  transition={{ duration: 3, repeat: Infinity, ease: "linear" }}
                />
                
                {/* Status - Smaller on mobile */}
                <motion.div
                  className="absolute bottom-2 right-2 sm:bottom-3 sm:right-3 flex items-center gap-1 sm:gap-2 bg-black/80 backdrop-blur-sm px-2 py-1 sm:px-3 sm:py-1.5 rounded-lg border border-green-400/30"
                  animate={{ scale: [1, 1.05, 1] }}
                  transition={{ duration: 2, repeat: Infinity }}
                >
                  <span className="w-1.5 h-1.5 sm:w-2 sm:h-2 rounded-full bg-green-400 animate-pulse" />
                  <span className="text-[8px] sm:text-xs text-green-400 font-mono font-medium">ACTIVE</span>
                </motion.div>

                {/* Company Logo */}
                <motion.div
                  className="absolute -bottom-1 -right-1 w-10 h-10 sm:w-14 sm:h-14 lg:w-16 lg:h-16 rounded-lg bg-black/90 backdrop-blur-sm border-2 border-green-400/30 flex items-center justify-center shadow-xl"
                  whileHover={{ scale: 1.15, rotate: 360 }}
                  transition={{ duration: 0.5 }}
                >
                  <img
                    src={PERSONAL_INFO.companyLogo}
                    alt="Company"
                    className="w-6 h-6 sm:w-8 sm:h-8 lg:w-10 lg:h-10 object-contain"
                  />
                </motion.div>
              </motion.div>

              {/* Floating Stats - Hacker Style */}
              <motion.div
                initial={{ opacity: 0, x: 20 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: 0.8 }}
                className="absolute -top-1 -right-1 sm:-top-4 sm:-right-4 bg-black/80 backdrop-blur-sm p-1.5 sm:p-3 lg:p-4 rounded-lg border border-green-500/30 shadow-xl shadow-green-500/10"
              >
                <div className="text-center">
                  <div className="flex items-center gap-0.5 sm:gap-1 text-green-400 text-[6px] sm:text-xs font-mono">
                    <Server className="w-2 h-2 sm:w-3 sm:h-3" />
                    <span className="hidden xs:inline">EXP</span>
                  </div>
                  <div className="text-xs sm:text-base lg:text-xl font-bold text-green-400">4.5+</div>
                  <div className="text-[6px] sm:text-xs text-gray-500 font-mono">Years</div>
                </div>
              </motion.div>

              <motion.div
                initial={{ opacity: 0, x: -20 }}
                animate={{ opacity: 1, x: 0 }}
                transition={{ delay: 0.9 }}
                className="absolute -bottom-1 -left-1 sm:-bottom-4 sm:-left-4 bg-black/80 backdrop-blur-sm p-1.5 sm:p-3 lg:p-4 rounded-lg border border-cyan-500/30 shadow-xl shadow-cyan-500/10"
              >
                <div className="text-center">
                  <div className="flex items-center gap-0.5 sm:gap-1 text-cyan-400 text-[6px] sm:text-xs font-mono">
                    <Code2 className="w-2 h-2 sm:w-3 sm:h-3" />
                    <span className="hidden xs:inline">PROJ</span>
                  </div>
                  <div className="text-xs sm:text-base lg:text-xl font-bold text-cyan-400">12+</div>
                  <div className="text-[6px] sm:text-xs text-gray-500 font-mono">Delivered</div>
                </div>
              </motion.div>
            </div>
          </motion.div>
        </div>
      </div>

      {/* Scroll Indicator - Hacker Style */}
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 1 }}
        className="absolute bottom-4 sm:bottom-8 left-1/2 -translate-x-1/2 cursor-pointer"
        onClick={() => scrollToSection("about")}
      >
        <motion.div
          animate={{ y: [0, 8, 0] }}
          transition={{ duration: 2, repeat: Infinity }}
          className="flex flex-col items-center gap-1 sm:gap-2 text-gray-600 hover:text-green-400 transition-colors"
        >
          <span className="text-[10px] sm:text-xs uppercase tracking-widest font-mono text-green-400/50">[ SCROLL ]</span>
          <ChevronDown className="w-4 h-4 sm:w-5 sm:h-5 text-green-400/50" />
        </motion.div>
      </motion.div>

      {/* Bottom Glow Effect */}
      <div className="absolute bottom-0 left-0 right-0 h-20 bg-gradient-to-t from-green-500/5 to-transparent pointer-events-none" />
    </section>
  );
};

export default Hero;